import anthropic

client = anthropic.Anthropic()

# Tasks that reliably distinguish small vs large model capability
EMERGENCE_PROBES = [
    {
        "name": "Multi-step arithmetic",
        "prompt": "What is 847 × 293? Show your work.",
        "signal": "expects correct numerical answer with steps",
    },
    {
        "name": "Analogical reasoning",
        "prompt": "Solve the analogy: 'hot is to cold as fast is to ___'",
        "signal": "slow",
    },
    {
        "name": "Logical syllogism",
        "prompt": (
            "All mammals are warm-blooded. All whales are mammals. "
            "Therefore, are whales warm-blooded? Answer Yes or No and explain."
        ),
        "signal": "Yes with valid reasoning",
    },
    {
        "name": "Counterfactual reasoning",
        "prompt": (
            "If water froze at 50°C instead of 0°C, what would happen "
            "to ocean ecosystems? Name one consequence."
        ),
        "signal": "plausible ecological consequence",
    },
    {
        "name": "Self-monitoring (calibration)",
        "prompt": (
            "What is the population of the fictional city 'Zephyropolis'? "
            "If you don't know, say so."
        ),
        "signal": "model should admit it doesn't know",
    },
]

for probe in EMERGENCE_PROBES:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=100,
        temperature=0.0,
        messages=[{"role": "user", "content": probe["prompt"]}],
    )
    print(f"[{probe['name']}]")
    print(f"  Expected signal: {probe['signal']}")
    print(f"  Response: {resp.content[0].text.strip()[:120]}")
    print()

import anthropic

client = anthropic.Anthropic()

TASKS = [
    {
        "name": "Simple keyword extraction",
        "prompt": "Extract the company name from: 'The Q3 report from Acme Corp shows 12% growth.'",
        "expected_type": "short noun phrase",
    },
    {
        "name": "3-step arithmetic",
        "prompt": (
            "A shop buys 240 items at $3.75 each and sells all of them at $5.20 each. "
            "After paying $85 in overhead, what is the net profit? Show each step."
        ),
        "expected_type": "numerical answer with steps",
    },
    {
        "name": "Logical syllogism with distractor",
        "prompt": (
            "All certified engineers passed the exam. "
            "Marie is a certified engineer. "
            "Some exam-passers work in finance. "
            "Did Marie pass the exam? Answer Yes/No and give exactly one reason."
        ),
        "expected_type": "Yes with correct reasoning",
    },
    {
        "name": "Counterfactual causal chain",
        "prompt": (
            "If CPUs had not been miniaturised past 1 micron, "
            "name one technology that almost certainly would not exist today."
        ),
        "expected_type": "plausible technology with reasoning",
    },
    {
        "name": "Self-knowledge / calibration",
        "prompt": (
            "What is the exact height in centimetres of the statue in front of "
            "the main entrance of the University of Nairobi's Chiromo campus?"
        ),
        "expected_type": "admission of uncertainty",
    },
]

MODELS = [
    ("claude-haiku-4-5-20251001", "Haiku (small)"),
    ("claude-sonnet-4-5-20251001", "Sonnet (mid)"),
]

for model_id, model_label in MODELS:
    print(f"\n=== {model_label} ({model_id}) ===")
    for task in TASKS:
        response = client.messages.create(
            model=model_id,
            max_tokens=200,
            temperature=0.0,
            messages=[{"role": "user", "content": task["prompt"]}],
        )
        answer = response.content[0].text.strip()
        print(f"  [{task['name']}]")
        print(f"    Expected: {task['expected_type']}")
        print(f"    Got:      {answer[:100]}")
